SELECT t3.`role_name` FROM t_user_role t1
 JOIN t_user t2 ON t1.`user_id` = t2.`user_id`
 JOIN t_role t3 ON t1.`role_id` = t3.`role_id`
WHERE t2.`user_name` = #{username}


and t1.comp_id = #{compId}

SELECT count(1) FROM (select 1 FROM t_user u LEFT JOIN t_user_info ui ON u.`user_id` = ui.`user_id` INNER JOIN t_user_role ur ON u.user_id = ur.user_id AND ui.`compID` = ur.`comp_id`
ur.role_id = #{model.roleId}
and ur.comp_id = #{model.compId}
and u.user_name like CONCAT("%", #{model.userName}, "%")
and ( user_name like CONCAT("%", #{fuzzy}, "%") )
GROUP BY u.`user_id`, ur.`comp_id`) t

SELECT ur.id, ur.role_id, ur.user_id, ur.comp_id, u.user_name ,ui.`realName`,u.status FROM t_user u LEFT JOIN t_user_info ui ON u.`user_id` = ui.`user_id` INNER JOIN t_user_role ur ON u.user_id = ur.user_id AND ui.`compID` = ur.`comp_id`
